const fs = require('fs');
const POSTED_FILE = '/files/posted-slugs.json';

function readPostedState() {
  try {
    const raw = fs.readFileSync(POSTED_FILE, 'utf8');
    const data = JSON.parse(raw);
    return {
      sharedSlugs: Array.isArray(data.sharedSlugs) ? data.sharedSlugs.slice() : [],
      nextIndex: typeof data.nextIndex === 'number' && !Number.isNaN(data.nextIndex) ? data.nextIndex : 0,
    };
  } catch (_e) {
    return { sharedSlugs: [], nextIndex: 0 };
  }
}

const staticData = $getWorkflowStaticData('global');
const fileState = readPostedState();

const sharedSlugs = fileState.sharedSlugs.length ? fileState.sharedSlugs : (Array.isArray(staticData.sharedSlugs) ? staticData.sharedSlugs.slice() : []);
let cursor = fileState.sharedSlugs.length
  ? fileState.nextIndex
  : (typeof staticData.nextIndex === 'number' && !Number.isNaN(staticData.nextIndex) ? staticData.nextIndex : 0);

const feed = $input.first().json;
const posts = Array.isArray(feed.posts) ? feed.posts : [];

if (!posts.length) {
  throw new Error('linkedin-posts.json returned no posts');
}

const sortedPosts = [...posts].sort((a, b) => {
  const aKey = String(a.publishedAt ?? a.date ?? a.slug ?? '');
  const bKey = String(b.publishedAt ?? b.date ?? b.slug ?? '');
  const byDate = aKey.localeCompare(bKey);
  if (byDate !== 0) return byDate;
  return String(a.slug ?? '').localeCompare(String(b.slug ?? ''));
});

const totalPosts = sortedPosts.length;
const sharedSet = new Set(sharedSlugs);
cursor = ((cursor % totalPosts) + totalPosts) % totalPosts;

let picked = null;
let pickedIndex = -1;

for (let offset = 0; offset < totalPosts; offset += 1) {
  const idx = (cursor + offset) % totalPosts;
  const candidate = sortedPosts[idx];
  if (candidate?.slug && !sharedSet.has(candidate.slug)) {
    picked = candidate;
    pickedIndex = idx;
    break;
  }
}

let catalogReset = false;
if (!picked) {
  catalogReset = true;
  picked = sortedPosts[0];
  pickedIndex = 0;
}

const nextIndex = (pickedIndex + 1) % totalPosts;

const postText = picked.text || picked.postText || '';
const url = picked.url;
const title = picked.title;
const description = postText.split('\n\n')[0]?.trim() || title;
const linkedinText = postText;

return [
  {
    json: {
      slug: picked.slug,
      title,
      url,
      description,
      linkedinText,
      topicCluster: picked.topicCluster,
      pickedIndex,
      nextIndex,
      totalPosts,
      catalogReset,
      feedGeneratedAt: feed.generatedAt,
      sharedSlugsCount: sharedSlugs.length,
      rotationSource: fileState.sharedSlugs.length ? 'file' : 'staticData-fallback',
    },
  },
];

const fs = require('fs');
const POSTED_FILE = '/files/posted-slugs.json';

const staticData = $getWorkflowStaticData('global');
const pick = $('Pick Next Post').first().json;

if (!pick?.slug) {
  throw new Error('Pick Next Post did not provide slug');
}

function readPostedState() {
  try {
    const raw = fs.readFileSync(POSTED_FILE, 'utf8');
    const data = JSON.parse(raw);
    return {
      sharedSlugs: Array.isArray(data.sharedSlugs) ? data.sharedSlugs.slice() : [],
      nextIndex: typeof data.nextIndex === 'number' && !Number.isNaN(data.nextIndex) ? data.nextIndex : 0,
    };
  } catch (_e) {
    return { sharedSlugs: [], nextIndex: 0 };
  }
}

function writePostedState(state) {
  fs.writeFileSync(
    POSTED_FILE,
    JSON.stringify(
      {
        sharedSlugs: state.sharedSlugs,
        nextIndex: state.nextIndex,
        lastPostedSlug: state.lastPostedSlug,
        lastPostedAt: state.lastPostedAt,
        updatedAt: new Date().toISOString(),
      },
      null,
      2,
    ),
    'utf8',
  );
}

const slug = pick.slug;
const prior = readPostedState();
let sharedSlugs;

if (pick.catalogReset) {
  sharedSlugs = [slug];
} else if (prior.sharedSlugs.includes(slug)) {
  sharedSlugs = prior.sharedSlugs.slice();
} else {
  sharedSlugs = [...prior.sharedSlugs, slug];
}

const nextIndex = pick.nextIndex;
const lastPostedAt = new Date().toISOString();

writePostedState({
  sharedSlugs,
  nextIndex,
  lastPostedSlug: slug,
  lastPostedAt,
});

staticData.sharedSlugs = sharedSlugs;
staticData.nextIndex = nextIndex;
staticData.lastPostedSlug = slug;
staticData.lastPostedAt = lastPostedAt;

return [
  {
    json: {
      ...pick,
      marked: true,
      totalShared: sharedSlugs.length,
      postedFile: POSTED_FILE,
    },
  },
];

const pick = $('Pick Next Post').first().json;
const item = $input.first();
const root = item?.json ?? {};

function errorBlob() {
  const chunks = [];
  const err = root.error ?? root;

  if (typeof err === 'string') {
    chunks.push(err);
  } else if (err && typeof err === 'object') {
    chunks.push(err.message, err.description, err.errorMessage, err.errorDescription);
    if (Array.isArray(err.messages)) chunks.push(...err.messages);
    if (Array.isArray(err.errors)) {
      for (const e of err.errors) {
        chunks.push(typeof e === 'string' ? e : JSON.stringify(e));
      }
    }
  }

  chunks.push(root.message, root.description, root.httpCode, root.statusCode, root.code);
  try {
    chunks.push(JSON.stringify(root));
  } catch (_e) {
    /* ignore */
  }

  return chunks.filter(Boolean).join(' ');
}

const blob = errorBlob();
const hasError = Boolean(root.error) || item?.error != null || root.errorMessage;

const errValue = root.error ?? root;
const normalizedMsg = (typeof errValue === 'string' ? errValue : errValue?.message || '').trim();

const isDuplicate =
  /DUPLICATE_POST/i.test(blob) ||
  /Duplicate post/i.test(blob) ||
  /duplicate of urn:li:share/i.test(blob) ||
  (/could not be processed by the service/i.test(blob) &&
    (/duplicate/i.test(blob) || /422/.test(blob) || root.httpCode === 422 || root.statusCode === 422)) ||
  normalizedMsg === 'Your request is invalid or could not be processed by the service';

if (!hasError) {
  return [{ json: { ...pick, linkedInResult: 'posted' } }];
}

if (isDuplicate) {
  const existingShareUrn = (blob.match(/urn:li:share:\d+/) || [])[0] ?? null;
  return [
    {
      json: {
        ...pick,
        linkedInResult: 'duplicate_skipped',
        existingShareUrn,
      },
    },
  ];
}

const err = root.error ?? root;
const message =
  (typeof err === 'string' ? err : err?.message) ||
  root.message ||
  blob ||
  'LinkedIn post failed';

throw new Error(message);
